import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthenticationManager {
  final SharedPreferences _prefs;

  AuthenticationManager(this._prefs);

  Future<void> login(String token, Map<String, dynamic> userData) async {
    await _prefs.setString('authToken', token);
    await _prefs.remove('userData');
    await _prefs.setString('userData', jsonEncode(userData));
  }

  Future<Map<String, dynamic>> getAuthData() async {
    final token = _prefs.getString('authToken');
    final userDataJson = _prefs.getString('userData');

    if (token != null && userDataJson != null) {
      return {
        'authToken': token,
        'userData': jsonDecode(userDataJson),
      };
    }

    return {};
  }

  Future<void> logout() async {
    await _prefs.remove('authToken');
    await _prefs.remove('userData');
  }
}